$script:subdivisionSequence = @(0.5, 0.25, 0.133333, 0.066667, 0.033333, 0.016667, 0.010417, 0.005556, 0.002778, 0.001389)  # 12h, 6h, 3.2h, 1.6h, 48m, 24m, 15m, 8m, 4m, 2m
