	Method = $null
	TenantId = $null
	ClientId = $null
	ClientSecret = $null  # SecureString
	CertThumbprint = $null
	CertPath = $null
	CertPassword = $null  # SecureString
	CertStoreLocation = 'CurrentUser'
	TokenIssueTime = $null
